import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatQty, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { PartnerDto, SalesReportRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-ban-hang';
const PAGE_ID = 'baocao-ban-hang';
const GROUP_OPTIONS = [
  { value: 'customer', label: 'Theo KH' },
  { value: 'material', label: 'Theo mặt hàng' },
];

const BaoCaoBanHangPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [customerId, setCustomerId] = useState('');
  const [groupBy, setGroupBy] = useState<'customer' | 'material'>('customer');
  const [partners, setPartners] = useState<PartnerDto[]>([]);
  const [rows, setRows] = useState<SalesReportRow[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      analyticsService
        .getPartners({ partnerType: 'Customer', pageSize: 500 })
        .then(d => {
          if (!cancelled) setPartners(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getSalesReport({
        fromDate,
        toDate,
        customerId: customerId || undefined,
        groupBy,
      })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi tải báo cáo'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, customerId, groupBy, dispatch]);

  const bm = groupBy === 'material';
  const tQ = rows.reduce((s, r) => s + (r.quantity ?? 0), 0);
  const tS = rows.reduce((s, r) => s + (r.subTotal ?? 0), 0);
  const tD = rows.reduce((s, r) => s + (r.discountAmount ?? 0), 0);
  const tV = rows.reduce((s, r) => s + (r.vatAmount ?? 0), 0);
  const tA = rows.reduce((s, r) => s + (r.totalAmount ?? 0), 0);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-customer`}>
              <Select
                label="Khách hàng"
                value={customerId}
                onChange={e => setCustomerId(e.target.value)}
                options={[
                  { value: '', label: 'Tất cả KH' },
                  ...partners.map(p => ({ value: p.id, label: `${p.code} — ${p.name}` })),
                ]}
                size="small"
              />
            </div>
            <div data-testid={`${TEST_ID}-field-groupBy`}>
              <Select
                label="Nhóm theo"
                value={groupBy}
                onChange={e => setGroupBy(e.target.value as 'customer' | 'material')}
                options={GROUP_OPTIONS}
                size="small"
              />
            </div>
          </>
        )}
      />
    ),
    [fromDate, toDate, customerId, groupBy, partners, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo bán hàng chi tiết"
      titleIconClass="fas fa-chart-line"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/accounting/sales-report/export-excel"
      exportParams={{ fromDate, toDate, customerId: customerId || undefined, groupBy }}
      exportFilename={`BaoCaoBanHang-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th className={reportStyles.colStt}>STT</th>
            {bm ? (
              <>
                <th>Mã hàng</th>
                <th>Tên hàng</th>
                <th>ĐVT</th>
                <th>Khách hàng</th>
              </>
            ) : (
              <>
                <th>Khách hàng</th>
                <th>Mặt hàng</th>
              </>
            )}
            <th className={reportStyles.colRight}>SL</th>
            <th className={reportStyles.colRight}>Doanh thu</th>
            <th className={reportStyles.colRight}>CK</th>
            <th className={reportStyles.colRight}>VAT</th>
            <th className={reportStyles.colRight}>Tổng TT</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={`${r.customerName}-${i}`}>
              <td className={reportStyles.colStt}>{i + 1}</td>
              {bm ? (
                <>
                  <td>{r.materialCode ?? '—'}</td>
                  <td>{r.materialName}</td>
                  <td>{r.unit ?? '—'}</td>
                  <td>{r.customerName}</td>
                </>
              ) : (
                <>
                  <td>{r.customerName}</td>
                  <td>{r.materialName}</td>
                </>
              )}
              <td className={reportStyles.colRight}>{formatQty(r.quantity)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.subTotal)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.discountAmount ?? 0)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.vatAmount)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.totalAmount)}</td>
            </tr>
          ))}
          {rows.length > 0 && (
            <tr className={reportStyles.rowTotal}>
              <td className={reportStyles.colStt} />
              <td colSpan={bm ? 4 : 2}>Tổng cộng</td>
              <td className={reportStyles.colRight}>{formatQty(tQ)}</td>
              <td className={reportStyles.colRight}>{formatVnd(tS)}</td>
              <td className={reportStyles.colRight}>{formatVnd(tD)}</td>
              <td className={reportStyles.colRight}>{formatVnd(tV)}</td>
              <td className={reportStyles.colRight}>{formatVnd(tA)}</td>
            </tr>
          )}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoBanHangPage;
